#!/usr/bin/env python3
"""
Patcher Métro-Taxi — Ajoute le système de broadcast 'Lancement Saint-Denis 13 juin 2026'.

Modifications :
1. backend/services/emails.py : ajoute send_launch_announcement_email()
2. backend/routes/admin.py    : ajoute import asyncio, import send_launch_announcement_email,
                                + 3 endpoints /admin/broadcast/launch-saint-denis/{preview,test,confirm}

Idempotent : si déjà patché, ne fait rien.
"""
import base64
import os
import sys
from datetime import datetime

PROJECT_ROOT = "/var/www/metro-taxi-app"
EMAILS_FILE = os.path.join(PROJECT_ROOT, "backend/services/emails.py")
ADMIN_FILE  = os.path.join(PROJECT_ROOT, "backend/routes/admin.py")

# Code à insérer (encodé en base64 pour zéro problème de caractères)
NEW_FUNCTION_B64 = """"""

NEW_ENDPOINTS_B64 = """"""

def log(msg, ok=True):
    prefix = "✅" if ok else "⚠️ "
    print(f"{prefix} {msg}")

def backup(path):
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    bak = f"{path}.bak.{ts}"
    with open(path, "rb") as src, open(bak, "wb") as dst:
        dst.write(src.read())
    log(f"Backup: {bak}")
    return bak

def patch_emails():
    if not os.path.exists(EMAILS_FILE):
        log(f"INTROUVABLE: {EMAILS_FILE}", ok=False)
        return False

    with open(EMAILS_FILE, "r", encoding="utf-8") as f:
        content = f.read()

    if "send_launch_announcement_email" in content:
        log("emails.py : déjà patché, je passe")
        return True

    backup(EMAILS_FILE)

    new_fn = base64.b64decode(NEW_FUNCTION_B64).decode("utf-8")

    # Insérer AVANT la section "# EMAIL PERSO ADMIN → CHAUFFEUR"
    anchor = "# EMAIL PERSO ADMIN"
    idx = content.find(anchor)
    if idx == -1:
        # Sinon, append à la fin
        log("Ancre non trouvée, append en fin de fichier", ok=False)
        new_content = content.rstrip() + "\n\n\n" + new_fn + "\n"
    else:
        # Remonter à la ligne ============ qui précède
        before = content[:idx].rstrip()
        # Retirer la ligne ===== finale (sera réinjectée)
        lines = before.split("\n")
        while lines and lines[-1].strip().startswith("# ===="):
            lines.pop()
        before = "\n".join(lines).rstrip()
        new_content = before + "\n\n\n" + new_fn + "\n\n# ============================================\n" + content[idx:]

    with open(EMAILS_FILE, "w", encoding="utf-8") as f:
        f.write(new_content)
    log("emails.py : send_launch_announcement_email() ajoutée")
    return True

def patch_admin():
    if not os.path.exists(ADMIN_FILE):
        log(f"INTROUVABLE: {ADMIN_FILE}", ok=False)
        return False

    with open(ADMIN_FILE, "r", encoding="utf-8") as f:
        content = f.read()

    changed = False

    if "/admin/broadcast/launch-saint-denis/preview" in content:
        log("admin.py : endpoints déjà présents")
    else:
        backup(ADMIN_FILE)

        # 1. Ajouter `import asyncio` si manquant
        if "\nimport asyncio\n" not in content:
            content = content.replace(
                "import math\nimport stripe",
                "import math\nimport asyncio\nimport stripe",
                1
            )
            log("  + import asyncio ajouté")

        # 2. Ajouter send_launch_announcement_email à l'import emails
        if "send_launch_announcement_email" not in content:
            content = content.replace(
                "send_admin_personal_email",
                "send_admin_personal_email, send_launch_announcement_email",
                1
            )
            log("  + import send_launch_announcement_email ajouté")

        # 3. Append les 3 endpoints à la fin
        new_ep = base64.b64decode(NEW_ENDPOINTS_B64).decode("utf-8")
        content = content.rstrip() + "\n\n" + new_ep + "\n"
        log("  + 3 endpoints broadcast ajoutés")

        with open(ADMIN_FILE, "w", encoding="utf-8") as f:
            f.write(content)
        log("admin.py : patché")
        changed = True

    return True

if __name__ == "__main__":
    print("=" * 60)
    print("PATCH MÉTRO-TAXI BROADCAST — Saint-Denis 13 juin 2026")
    print("=" * 60)
    ok1 = patch_emails()
    print()
    ok2 = patch_admin()
    print()
    if ok1 and ok2:
        log("PATCH APPLIQUÉ AVEC SUCCÈS")
        print()
        print("Redémarre le backend maintenant :")
        print("  pm2 restart all --update-env")
        print()
        sys.exit(0)
    else:
        log("ERREUR DURANT LE PATCH", ok=False)
        sys.exit(1)
